  <script>/*=== 5G TOLL FREE NUMBER ====
Audiences & #:
t=pure | 8663964999
t=plus | 8776153777
t=dual | 8002955055
Active Hours: 
- Monday to Saturday: 8AMâ€“10PM EST
- Sunday: 9AMâ€“10PM EST
==============================*/

function displayTFN() {
  const now = new Date();
  const options = {
    timeZone: "America/New_York",
    hour: "numeric",
    minute: "numeric",
    weekday: "long",
    hourCycle: "h23",
  };

  const getTime = new Intl.DateTimeFormat("en-US", options).formatToParts(now);

  let day = "";
  let hour = 0;
  let min = 0;

  for (const part of getTime) {
    if (part.type === "weekday") {
      day = part.value;
    } else if (part.type === "hour") {
      hour = parseInt(part.value, 10);
    } else if (part.type === "minute") {
      min = parseInt(part.value, 10);
    }
  }

  console.log("TFN " + day + " | " + hour + ":" + min);

  const days = [
    "Sunday",
    "Monday",
    "Tuesday",
    "Wednesday",
    "Thursday",
    "Friday",
    "Saturday",
  ];
  const dayIndex = days.indexOf(day);

  let time = false;
  const hourNow = hour + min / 60;

  if (dayIndex >= 1 && dayIndex <= 6) {
    if (hourNow >= 8 && hourNow < 22) {
      time = true;
    }
  } else if (dayIndex === 0) {
    // Sunday
    if (hourNow >= 9 && hourNow < 22) {
      time = true;
    }
  }

  // Check for query parameter
  const url = new URLSearchParams(window.location.search);
  const getParam = url.get("t");
  let param = "";
//   const phoneNum = document.getElementById("phone-number");
  const phoneNumerElements = document.querySelectorAll('[data-role="phone-number"]');

  /************************  NEW FOR GNAV - START ************************/
  let gnavPhone = "";
  /************************  NEW FOR GNAV - END ************************/

  phoneNumerElements.forEach((phoneNum) => {
    if (getParam === "pure") {
      phoneNum.innerHTML = "1-866-396-4999";
      phoneNum.setAttribute("href", "tel:1-866-396-4999");
      param = true;
      gnavPhone = "1-866-396-4999";
      console.log("TFN audience: " + getParam);
    } else if (getParam === "plus") {
      phoneNum.innerHTML = "1-877-615-3777";
      phoneNum.setAttribute("href", "tel:1-877-615-3777");
      param = true;
      gnavPhone = "1-877-615-3777";
      console.log("TFN audience: " + getParam);
    } else if (getParam === "dual") {
      phoneNum.innerHTML = "1-800-295-5055";
      phoneNum.setAttribute("href", "tel:1-800-295-5055");
      param = true;
      gnavPhone = "1-800-295-5055";
      console.log("TFN audience: " + getParam);
    } else if (getParam === null) {
      console.log("TFN missing audience");
      param = false;
    } else {
      console.log("TFN audience is invalid");
      param = false;
    }
  });

  /************************  NEW FOR GNAV - START ************************/
  if (gnavPhone != "") {
    const gnavCallUsLink = document.querySelector(".gnav20-sub-nav-call-link");
    const gnavCallUsCTA = document.querySelector(".gnav20-sub-nav-button");
    if (gnavCallUsLink && gnavCallUsCTA) {
      gnavCallUsLink.textContent = "Call Us: " + gnavPhone;
      gnavCallUsLink.href = "tel:" + gnavPhone;
      gnavCallUsLink.dataset["track"] =
        "global nav:call us:" + gnavPhone + "|" + getParam;
      gnavCallUsCTA.href = "tel:" + gnavPhone;
    }
  }
  /************************  NEW FOR GNAV - END ************************/

  return time && param;
}

document.addEventListener("DOMContentLoaded", () => {
  const tfnBar = document.getElementById("toll-free-enable");

  if (tfnBar) {
    if (displayTFN()) {
      tfnBar.style.display = "flex";
      console.log("TFN is showing!");
    } else if (window.location.href.indexOf("salesaem-prod-author") > -1) {
      tfnBar.innerHTML =
        "<p class='u-fontDisplay u-textLineHeightNormal u-text--xs20 u-text--md24 u-textBold u-textCenter'>&#9888; 5G TFN Banner &#9888; </p>";
      tfnBar.style.display = "flex";
      console.log("TFN Author is Showing");
    } else {
      tfnBar.style.display = "none";
      console.log("TFN is offline");
    }
  } else {
    console.warn("TFN element not found.");
  }
});

/************************  NEW FOR GNAV - START ************************/
window.GNAV_IS_READY
  ? displayTFN()
  : document.addEventListener("gnavReady", displayTFN);
/************************  NEW FOR GNAV - END ************************/
</script>
