  <script>document.body.addEventListener("refresh-contextHub", () => {
document.addEventListener('click', function(event) {
    if (event.target.closest('.discount-toggle-controls')) {
        toggleDiscountContainer(event.target);
    }
});

function toggleDiscountContainer(target) {
    var discountToggleSticky = target.closest(".discount-toggle-sticky");
    if (discountToggleSticky) {
        var discountContainer = discountToggleSticky.querySelector(".discount-toggle-container");
        var discountControls = discountToggleSticky.querySelector(".discount-toggle-controls");

        if (discountContainer) {
            discountContainer.classList.toggle("discount-container-closed");
        }
        if (discountControls) {
            discountControls.classList.toggle("discount-controls-closed");
        }
    }
}
});</script>
